{
  "name": "Jam'iya Manager",
  "description": "A comprehensive ROSCA (Rotating Savings and Credit Association) management tool. Tracks monthly contributions, member payouts, and financial status with persistent storage."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Member {
  id: string;
  name: string;
  order: number; // 0-based index for payout month
}

export interface PaymentStatus {
  [memberId: string]: boolean; // true if paid
}

export interface MonthRecord {
  monthIndex: number;
  payments: PaymentStatus;
  payoutCompleted: boolean; // Did the recipient receive the pot?
}

export interface AssociationData {
  id: string;
  name: string;
  startDate: string; // ISO Date string (YYYY-MM)
  amountPerPerson: number;
  members: Member[];
  currentMonthIndex: number;
  history: { [monthIndex: number]: MonthRecord };
}

export enum AppScreen {
  SETUP = 'SETUP',
  DASHBOARD = 'DASHBOARD'
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'outline';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '', 
  ...props 
}) => {
  const baseStyle = "px-4 py-3 rounded-xl font-bold transition-all duration-200 active:scale-95 flex items-center justify-center gap-2 shadow-sm disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-primary text-white hover:bg-emerald-700 shadow-emerald-200",
    secondary: "bg-white text-gray-700 border border-gray-200 hover:bg-gray-50",
    danger: "bg-red-50 text-red-600 hover:bg-red-100 border border-red-100",
    outline: "border-2 border-primary text-primary hover:bg-emerald-50"
  };

  return (
    <button 
      className={`${baseStyle} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  error?: string;
}

export const Input: React.FC<InputProps> = ({ label, error, className = '', ...props }) => {
  return (
    <div className="flex flex-col gap-1 w-full">
      {label && <label className="text-sm font-semibold text-gray-700">{label}</label>}
      <input
        className={`w-full px-4 py-3 rounded-xl border bg-white focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all ${error ? 'border-red-500' : 'border-gray-200 focus:border-primary'} ${className}`}
        {...props}
      />
      {error && <span className="text-xs text-red-500">{error}</span>}
    </div>
  );
};

export const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat('ar-EG', {
    style: 'currency',
    currency: 'EGP',
    maximumFractionDigits: 0,
  }).format(amount);
};

export const getMonthName = (startDateStr: string, monthOffset: number) => {
  const date = new Date(startDateStr);
  date.setMonth(date.getMonth() + monthOffset);
  return new Intl.DateTimeFormat('ar-EG', { month: 'long', year: 'numeric' }).format(date);
};

export const generateId = () => {
  return Math.random().toString(36).substr(2, 9);
};

import React, { useState, useEffect } from 'react';
import { AppScreen, AssociationData, Member, MonthRecord } from './types';
import { Trash2, Users, Calendar, Plus, Save, ArrowRight, Wallet, CheckCircle, Lock, RefreshCw, AlertCircle } from 'lucide-react';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { formatCurrency, getMonthName, generateId } from './utils/helpers';

// Storage Key
const STORAGE_KEY = 'jamiya_app_data_v1';

const App = () => {
  // State
  const [screen, setScreen] = useState<AppScreen>(AppScreen.SETUP);
  const [data, setData] = useState<AssociationData | null>(null);

  // Loading from LocalStorage
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        setData(JSON.parse(savedData));
        setScreen(AppScreen.DASHBOARD);
      } catch (e) {
        console.error("Failed to parse saved data");
      }
    }
  }, []);

  // Saving to LocalStorage
  useEffect(() => {
    if (data) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    }
  }, [data]);

  // --- Actions ---

  const handleCreateAssociation = (name: string, amount: number, startDate: string, members: string[]) => {
    const memberObjects: Member[] = members.map((m, index) => ({
      id: generateId(),
      name: m,
      order: index
    }));

    const newData: AssociationData = {
      id: generateId(),
      name,
      amountPerPerson: amount,
      startDate,
      members: memberObjects,
      currentMonthIndex: 0,
      history: {} // Start empty
    };

    setData(newData);
    setScreen(AppScreen.DASHBOARD);
  };

  const handleReset = () => {
    if (confirm('هل أنت متأكد من حذف الجمعية والبدء من جديد؟ لا يمكن التراجع عن هذا الإجراء.')) {
      localStorage.removeItem(STORAGE_KEY);
      setData(null);
      setScreen(AppScreen.SETUP);
    }
  };

  // --- Views ---

  if (screen === AppScreen.SETUP) {
    return <SetupView onCreate={handleCreateAssociation} />;
  }

  if (screen === AppScreen.DASHBOARD && data) {
    return <DashboardView data={data} onUpdate={setData} onReset={handleReset} />;
  }

  return null;
};

// --- Sub-Components (Defined here to keep file count low as requested, but separated logic) ---

/**
 * Screen 1: Setup View
 */
const SetupView: React.FC<{ onCreate: (name: string, amount: number, date: string, members: string[]) => void }> = ({ onCreate }) => {
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [date, setDate] = useState(new Date().toISOString().slice(0, 7)); // YYYY-MM
  const [memberName, setMemberName] = useState('');
  const [members, setMembers] = useState<string[]>([]);

  const addMember = () => {
    if (memberName.trim()) {
      setMembers([...members, memberName.trim()]);
      setMemberName('');
    }
  };

  const removeMember = (index: number) => {
    setMembers(members.filter((_, i) => i !== index));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !amount || members.length < 2) {
      alert("الرجاء إكمال جميع البيانات وإضافة عضوين على الأقل");
      return;
    }
    onCreate(name, parseFloat(amount), date, members);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 max-w-md mx-auto">
      <div className="bg-white rounded-3xl shadow-xl w-full p-6 space-y-6">
        <div className="text-center space-y-2">
          <div className="bg-emerald-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto text-primary mb-4">
            <Users size={32} />
          </div>
          <h1 className="text-2xl font-bold text-gray-800">إنشاء جمعية جديدة</h1>
          <p className="text-gray-500 text-sm">أدخل تفاصيل الجمعية والأعضاء للبدء</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <Input 
            label="اسم الجمعية" 
            placeholder="مثال: جمعية العائلة" 
            value={name} 
            onChange={(e) => setName(e.target.value)} 
          />

          <div className="grid grid-cols-2 gap-4">
            <Input 
              label="القسط الشهري" 
              type="number" 
              placeholder="1000" 
              value={amount} 
              onChange={(e) => setAmount(e.target.value)} 
            />
            <Input 
              label="شهر البداية" 
              type="month" 
              value={date} 
              onChange={(e) => setDate(e.target.value)} 
            />
          </div>

          <div className="border-t border-gray-100 pt-4">
            <label className="text-sm font-semibold text-gray-700 block mb-2">إضافة الأعضاء (بالترتيب)</label>
            <div className="flex gap-2 mb-4">
              <Input 
                placeholder="اسم العضو" 
                value={memberName} 
                onChange={(e) => setMemberName(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), addMember())}
              />
              <Button type="button" onClick={addMember} className="aspect-square p-0 w-[50px]">
                <Plus size={24} />
              </Button>
            </div>

            <div className="bg-gray-50 rounded-xl p-2 max-h-48 overflow-y-auto space-y-2">
              {members.length === 0 && <p className="text-center text-gray-400 text-sm py-4">لم يتم إضافة أعضاء بعد</p>}
              {members.map((m, idx) => (
                <div key={idx} className="flex items-center justify-between bg-white p-3 rounded-lg border border-gray-100 shadow-sm animate-in fade-in slide-in-from-bottom-2">
                  <div className="flex items-center gap-3">
                    <span className="bg-emerald-100 text-primary w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">
                      {idx + 1}
                    </span>
                    <span className="font-medium text-gray-700">{m}</span>
                  </div>
                  <button type="button" onClick={() => removeMember(idx)} className="text-red-400 hover:text-red-600">
                    <Trash2 size={18} />
                  </button>
                </div>
              ))}
            </div>
          </div>

          <Button type="submit" fullWidth className="mt-4" disabled={members.length < 2}>
            حفظ وإنشاء الجمعية
          </Button>
        </form>
      </div>
    </div>
  );
};

/**
 * Screen 2: Dashboard View
 */
const DashboardView: React.FC<{ data: AssociationData; onUpdate: (d: AssociationData) => void; onReset: () => void }> = ({ data, onUpdate, onReset }) => {
  // Current Month Logic
  const currentIndex = data.currentMonthIndex;

  // Get history for current month or initialize empty
  const currentHistory: MonthRecord = data.history[currentIndex] || {
    monthIndex: currentIndex,
    payments: {},
    payoutCompleted: false
  };

  const recipientMember = data.members[currentIndex % data.members.length];
  const isFinished = currentIndex >= data.members.length; // Logic if limited to 1 round, usually ROSCAs loop or stop. Let's assume loop or stop based on requirements. User said "until months end", implying limited rounds usually equal to member count.

  const totalExpected = data.amountPerPerson * data.members.length;
  const paidCount = Object.values(currentHistory.payments).filter(Boolean).length;
  const totalCollected = paidCount * data.amountPerPerson;
  const remaining = totalExpected - totalCollected;
  const isCollectionComplete = remaining === 0;

  // Actions
  const togglePayment = (memberId: string) => {
    if (currentHistory.payoutCompleted) return; // Lock payments if payout done

    const newPayments = { ...currentHistory.payments, [memberId]: !currentHistory.payments[memberId] };
    const newHistory = {
      ...data.history,
      [currentIndex]: {
        ...currentHistory,
        payments: newPayments
      }
    };
    onUpdate({ ...data, history: newHistory });
  };

  const handlePayoutToggle = () => {
    if (!isCollectionComplete) return;

    const newHistory = {
      ...data.history,
      [currentIndex]: {
        ...currentHistory,
        payoutCompleted: !currentHistory.payoutCompleted
      }
    };
    onUpdate({ ...data, history: newHistory });
  };

  const moveToNextMonth = () => {
    if (!currentHistory.payoutCompleted) return;

    // Check if we reached the end
    if (currentIndex + 1 >= data.members.length) {
       alert("تم اكتمال الجمعية بالكامل!");
       // Optional: You could allow reset here or just stay in finished state
       return;
    }

    onUpdate({
      ...data,
      currentMonthIndex: currentIndex + 1
    });
  };

  if (isFinished) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 text-center">
        <div className="bg-green-100 w-24 h-24 rounded-full flex items-center justify-center text-green-600 mb-6">
          <CheckCircle size={48} />
        </div>
        <h2 className="text-3xl font-bold text-gray-800 mb-2">اكتملت الجمعية!</h2>
        <p className="text-gray-500 mb-8">تم تسليم جميع المبالغ المستحقة لجميع الأعضاء.</p>
        <Button onClick={onReset} variant="outline">
          بدء جمعية جديدة
        </Button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      {/* Header Info Card */}
      <div className="bg-primary text-white p-6 rounded-b-[2.5rem] shadow-lg relative overflow-hidden">
        {/* Background Pattern */}
        <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
           <svg className="w-full h-full" viewBox="0 0 100 100" preserveAspectRatio="none">
             <path d="M0 100 C 20 0 50 0 100 100 Z" fill="white" />
           </svg>
        </div>

        <div className="relative z-10">
          <div className="flex justify-between items-start mb-6">
            <div>
              <h1 className="text-2xl font-bold">{data.name}</h1>
              <div className="flex items-center gap-2 opacity-90 text-sm mt-1">
                <Calendar size={14} />
                <span>{getMonthName(data.startDate, currentIndex)}</span>
              </div>
            </div>
            <button onClick={onReset} className="p-2 bg-white/10 rounded-full hover:bg-white/20 transition-colors">
              <RefreshCw size={18} />
            </button>
          </div>

          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4">
              <p className="text-emerald-100 text-xs mb-1">المبلغ المحصل</p>
              <p className="text-2xl font-bold font-mono">{formatCurrency(totalCollected)}</p>
            </div>
            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4">
              <p className="text-emerald-100 text-xs mb-1">المتبقي</p>
              <p className="text-2xl font-bold font-mono">{formatCurrency(remaining)}</p>
            </div>
          </div>

          {/* Recipient Section */}
          <div className="bg-white text-gray-800 rounded-2xl p-4 shadow-lg flex items-center justify-between">
            <div>
              <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider mb-1">مستلم الشهر</p>
              <p className="text-xl font-bold text-primary">{recipientMember.name}</p>
            </div>
            <div className="flex flex-col items-end">
               <label className={`flex items-center gap-2 px-3 py-1 rounded-full cursor-pointer transition-all ${
                 currentHistory.payoutCompleted 
                  ? 'bg-green-100 text-green-700' 
                  : isCollectionComplete 
                    ? 'bg-emerald-600 text-white shadow-md' 
                    : 'bg-gray-100 text-gray-400 cursor-not-allowed'
               }`}>
                 <input 
                   type="checkbox" 
                   checked={currentHistory.payoutCompleted} 
                   onChange={handlePayoutToggle}
                   disabled={!isCollectionComplete}
                   className="hidden"
                 />
                 <span className="text-sm font-bold">{currentHistory.payoutCompleted ? 'تم التسليم' : 'تسليم'}</span>
                 {currentHistory.payoutCompleted ? <CheckCircle size={16} /> : <Wallet size={16} />}
               </label>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="p-4 space-y-4 max-w-lg mx-auto mt-2">

        {/* Progress Bar */}
        <div className="w-full bg-gray-200 rounded-full h-2.5 mb-2">
          <div 
            className="bg-primary h-2.5 rounded-full transition-all duration-500 ease-out" 
            style={{ width: `${(totalCollected / totalExpected) * 100}%` }}
          ></div>
        </div>
        <p className="text-xs text-center text-gray-500 mb-6">
          تم تحصيل {paidCount} من {data.members.length} مشتركين
        </p>

        {/* Member List */}
        <div className="space-y-3">
          {data.members.map((member) => {
            const isPaid = !!currentHistory.payments[member.id];
            // Calculate which month this member receives money
            const payoutMonthName = getMonthName(data.startDate, member.order);
            const isRecipient = member.id === recipientMember.id;

            return (
              <div 
                key={member.id}
                onClick={() => togglePayment(member.id)}
                className={`
                  relative flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer select-none
                  ${isPaid 
                    ? 'bg-white border-emerald-200 shadow-sm' 
                    : 'bg-white border-gray-100 shadow-sm opacity-90'
                  }
                  ${isRecipient ? 'ring-2 ring-yellow-400 ring-offset-2' : ''}
                `}
              >
                <div className="flex items-center gap-4">
                  <div className={`
                    w-12 h-12 rounded-full flex items-center justify-center text-lg font-bold transition-colors
                    ${isPaid ? 'bg-emerald-100 text-emerald-600' : 'bg-gray-100 text-gray-400'}
                  `}>
                    {isPaid ? <CheckCircle size={24} /> : <span className="text-sm">{member.order + 1}</span>}
                  </div>
                  <div>
                    <h3 className={`font-bold text-lg ${isPaid ? 'text-gray-800' : 'text-gray-600'}`}>
                      {member.name}
                      {isRecipient && <span className="mr-2 text-xs bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded-full">المستلم</span>}
                    </h3>
                    <p className="text-xs text-gray-400 flex items-center gap-1">
                      <Calendar size={10} />
                      موعد القبض: {payoutMonthName}
                    </p>
                  </div>
                </div>

                <div className={`
                  w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors
                  ${isPaid 
                    ? 'bg-emerald-500 border-emerald-500' 
                    : 'border-gray-300'
                  }
                `}>
                   {isPaid && <CheckCircle size={14} className="text-white" />}
                </div>
              </div>
            );
          })}
        </div>

        {/* Next Month Action */}
        {currentHistory.payoutCompleted && (
          <div className="fixed bottom-6 left-0 right-0 px-6 max-w-lg mx-auto">
             <Button 
               onClick={moveToNextMonth} 
               fullWidth 
               className="shadow-xl shadow-emerald-200 animate-bounce"
             >
               <span>بدء الشهر التالي</span>
               <ArrowRight size={20} className="mr-1" />
             </Button>
          </div>
        )}

        {!isCollectionComplete && !currentHistory.payoutCompleted && (
           <div className="h-12"></div> /* Spacer */
        )}
      </div>
    </div>
  );
};

export default App;

