import android.view.View;
import android.view.ViewGroup;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ImageButton;
import android.widget.TextView;
import android.widget.Toast;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import java.util.ArrayList;
import java.util.List;

public class SetupActivity extends AppCompatActivity {

    private DatabaseHelper dbHelper;
    private EditText etName, etAmount, etDate, etMemberName;
    private Button btnAddMember, btnSave;
    private RecyclerView rvMembers;
    private MemberAdapter adapter;
    private List<String> tempMembers = new ArrayList<>();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_setup);

        dbHelper = new DatabaseHelper(this);

        // Check if already setup, go to Dashboard directly
        if (dbHelper.isSetupDone()) {
            startActivity(new Intent(this, DashboardActivity.class));
            finish();
            return;
        }

        initViews();
    }

    private void initViews() {
        etName = findViewById(R.id.etAssocName);
        etAmount = findViewById(R.id.etAmount);
        etDate = findViewById(R.id.etStartDate); // Format YYYY-MM
        etMemberName = findViewById(R.id.etMemberName);
        btnAddMember = findViewById(R.id.btnAddMember);
        btnSave = findViewById(R.id.btnSave);
        rvMembers = findViewById(R.id.rvSetupMembers);

        // Setup RecyclerView
        adapter = new MemberAdapter();
        rvMembers.setLayoutManager(new LinearLayoutManager(this));
        rvMembers.setAdapter(adapter);

        btnAddMember.setOnClickListener(v -> {
            String name = etMemberName.getText().toString().trim();
            if (!name.isEmpty()) {
                tempMembers.add(name);
                adapter.notifyItemInserted(tempMembers.size() - 1);
                etMemberName.setText("");
            }
        });

        btnSave.setOnClickListener(v -> saveAndStart());
    }

    private void saveAndStart() {
        String name = etName.getText().toString().trim();
        String amountStr = etAmount.getText().toString().trim();
        String date = etDate.getText().toString().trim();

        if (name.isEmpty() || amountStr.isEmpty() || date.isEmpty() || tempMembers.size() < 2) {
            Toast.makeText(this, "الرجاء إكمال البيانات وإضافة عضوين على الأقل", Toast.LENGTH_LONG).show();
            return;
        }

        // Save Settings
        dbHelper.saveSetting(DatabaseHelper.KEY_ASSOC_NAME, name);
        dbHelper.saveSetting(DatabaseHelper.KEY_AMOUNT, amountStr);
        dbHelper.saveSetting(DatabaseHelper.KEY_START_DATE, date);
        dbHelper.saveSetting(DatabaseHelper.KEY_CURRENT_MONTH_IDX, "0");

        // Save Members (Order is preserved by list index)
        for (int i = 0; i < tempMembers.size(); i++) {
            dbHelper.addMember(tempMembers.get(i), i);
        }

        // Go to Dashboard
        startActivity(new Intent(this, DashboardActivity.class));
        finish();
    }

    // Inner Adapter Class for simplicity
    class MemberAdapter extends RecyclerView.Adapter<MemberAdapter.VH> {
        @NonNull
        @Override
        public VH onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
            View v = LayoutInflater.from(parent.getContext()).inflate(android.R.layout.simple_list_item_1, parent, false);
            return new VH(v);
        }

        @Override
        public void onBindViewHolder(@NonNull VH holder, int position) {
            holder.text.setText((position + 1) + ". " + tempMembers.get(position));
        }

        @Override
        public int getItemCount() { return tempMembers.size(); }

        class VH extends RecyclerView.ViewHolder {
            TextView text;
            public VH(View itemView) {
                super(itemView);
                text = itemView.findViewById(android.R.id.text1);
            }
        }
    }
}

package com.example.jamiya;

import android.content.Intent;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.ImageButton;
import android.widget.TextView;
import android.widget.Toast;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import java.text.NumberFormat;
import java.text.SimpleDateFormat;
import java.util.Calendar;
import java.util.List;
import java.util.Locale;

public class DashboardActivity extends AppCompatActivity {

    private DatabaseHelper dbHelper;
    private TextView tvAssocName, tvCurrentDate, tvCollected, tvRemaining, tvRecipientName;
    private CheckBox cbPayoutDone;
    private RecyclerView rvMembers;
    private Button btnReset;
    private DashboardAdapter adapter;
    private List<Member> memberList;

    // State
    private int currentMonthIdx;
    private double amountPerPerson;
    private String startDateStr;
    private int paidCount = 0;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_dashboard);

        dbHelper = new DatabaseHelper(this);
        initViews();
        loadData();
    }

    private void initViews() {
        tvAssocName = findViewById(R.id.tvDashAssocName);
        tvCurrentDate = findViewById(R.id.tvDashDate);
        tvCollected = findViewById(R.id.tvDashCollected);
        tvRemaining = findViewById(R.id.tvDashRemaining);
        tvRecipientName = findViewById(R.id.tvRecipientName);
        cbPayoutDone = findViewById(R.id.cbPayoutDone);
        rvMembers = findViewById(R.id.rvDashMembers);
        btnReset = findViewById(R.id.btnReset);

        rvMembers.setLayoutManager(new LinearLayoutManager(this));

        // Logic for "Done" button (Payout)
        cbPayoutDone.setOnClickListener(v -> handlePayoutClick());

        btnReset.setOnClickListener(v -> {
            new AlertDialog.Builder(this)
                .setTitle("حذف الجمعية")
                .setMessage("هل أنت متأكد؟ سيتم حذف جميع البيانات والبدء من جديد.")
                .setPositiveButton("حذف", (d, w) -> {
                    dbHelper.resetAllData();
                    startActivity(new Intent(this, SetupActivity.class));
                    finish();
                })
                .setNegativeButton("إلغاء", null)
                .show();
        });
    }

    private void loadData() {
        // Load Settings
        String name = dbHelper.getSetting(DatabaseHelper.KEY_ASSOC_NAME);
        startDateStr = dbHelper.getSetting(DatabaseHelper.KEY_START_DATE);
        String amountStr = dbHelper.getSetting(DatabaseHelper.KEY_AMOUNT);
        amountPerPerson = Double.parseDouble(amountStr);
        currentMonthIdx = dbHelper.getCurrentMonthIndex();

        tvAssocName.setText(name);

        // Calculate Date
        String dateDisplay = calculateMonthDate(startDateStr, currentMonthIdx);
        tvCurrentDate.setText(dateDisplay);

        // Load Members
        memberList = dbHelper.getAllMembers();

        // Determine Recipient (Round Robin)
        if (!memberList.isEmpty()) {
            Member recipient = memberList.get(currentMonthIdx % memberList.size());
            tvRecipientName.setText(recipient.getName());
        }

        // Check payment status for this month
        paidCount = 0;
        for (Member m : memberList) {
            boolean isPaid = dbHelper.isMemberPaid(m.getId(), currentMonthIdx);
            m.setPaidForCurrentMonth(isPaid);
            if (isPaid) paidCount++;
        }

        updateSummary();

        // Bind Adapter
        if (adapter == null) {
            adapter = new DashboardAdapter();
            rvMembers.setAdapter(adapter);
        } else {
            adapter.notifyDataSetChanged();
        }
    }

    private void updateSummary() {
        double collected = paidCount * amountPerPerson;
        double total = memberList.size() * amountPerPerson;
        double remaining = total - collected;

        NumberFormat nf = NumberFormat.getCurrencyInstance(new Locale("ar", "EG"));
        tvCollected.setText(nf.format(collected));
        tvRemaining.setText(nf.format(remaining));

        // Enable "Done" checkbox only if fully collected
        boolean isComplete = (remaining == 0);
        cbPayoutDone.setEnabled(isComplete);
        cbPayoutDone.setChecked(false); // Reset visual state

        if (!isComplete) {
            cbPayoutDone.setText("بانتظار التحصيل...");
        } else {
            cbPayoutDone.setText("تسليم الجمعية (إغلاق الشهر)");
        }
    }

    private void handlePayoutClick() {
        if (!cbPayoutDone.isChecked()) return; // User unchecked it

        new AlertDialog.Builder(this)
            .setTitle("تأكيد التسليم")
            .setMessage("هل تم تسليم المبلغ بالكامل؟ سيتم الانتقال للشهر التالي.")
            .setPositiveButton("نعم، تم التسليم", (d, w) -> {
                dbHelper.incrementCurrentMonth();
                Toast.makeText(this, "بدء الشهر الجديد", Toast.LENGTH_SHORT).show();
                // Reload activity to refresh data for next month
                recreate(); 
            })
            .setNegativeButton("إلغاء", (d, w) -> cbPayoutDone.setChecked(false))
            .show();
    }

    private String calculateMonthDate(String start, int offset) {
        try {
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM", Locale.US);
            Calendar cal = Calendar.getInstance();
            cal.setTime(sdf.parse(start));
            cal.add(Calendar.MONTH, offset);
            SimpleDateFormat displayFormat = new SimpleDateFormat("MMMM yyyy", new Locale("ar"));
            return displayFormat.format(cal.getTime());
        } catch (Exception e) { return start; }
    }

    // --- Adapter ---
    class DashboardAdapter extends RecyclerView.Adapter<DashboardAdapter.VH> {
        @NonNull
        @Override
        public VH onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
            View v = LayoutInflater.from(parent.getContext()).inflate(R.layout.item_member_dashboard, parent, false);
            return new VH(v);
        }

        @Override
        public void onBindViewHolder(@NonNull VH holder, int position) {
            Member m = memberList.get(position);

            holder.tvName.setText(m.getName());

            // Calculate payout date for this specific member
            String payoutDate = calculateMonthDate(startDateStr, m.getOrder());
            holder.tvDate.setText("موعد القبض: " + payoutDate);

            // Styling based on Paid Status
            if (m.isPaidForCurrentMonth()) {
                holder.itemView.setBackgroundResource(R.drawable.bg_card_paid); // Greenish
                holder.cbPaid.setChecked(true);
            } else {
                holder.itemView.setBackgroundResource(R.drawable.bg_card); // White
                holder.cbPaid.setChecked(false);
            }

            // Highlight Recipient
            if (m.getId() == memberList.get(currentMonthIdx % memberList.size()).getId()) {
                holder.tvRole.setVisibility(View.VISIBLE);
                holder.tvRole.setText("المستلم هذا الشهر");
            } else {
                holder.tvRole.setVisibility(View.GONE);
            }

            // Checkbox Listener
            holder.cbPaid.setOnClickListener(v -> {
                boolean isChecked = holder.cbPaid.isChecked();
                dbHelper.setPaymentStatus(m.getId(), currentMonthIdx, isChecked);
                m.setPaidForCurrentMonth(isChecked);

                // Recalculate Logic
                paidCount = isChecked ? paidCount + 1 : paidCount - 1;
                updateSummary();
                notifyItemChanged(position); // Refresh color
            });
        }

        @Override
        public int getItemCount() { return memberList.size(); }

        class VH extends RecyclerView.ViewHolder {
            TextView tvName, tvDate, tvRole;
            CheckBox cbPaid;
            public VH(View itemView) {
                super(itemView);
                tvName = itemView.findViewById(R.id.tvMemberDashName);
                tvDate = itemView.findViewById(R.id.tvMemberDashDate);
                tvRole = itemView.findViewById(R.id.tvMemberRole);
                cbPaid = itemView.findViewById(R.id.cbMemberPaid);
            }
        }
    }
}

package com.example.jamiya;

import android.app.DatePickerDialog;
import android.content.Intent;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.List;
import java.util.Locale;

public class SetupActivity extends AppCompatActivity {

    private DatabaseHelper dbHelper;
    private EditText etName, etAmount, etDate, etMemberName;
    private Button btnAddMember, btnSave;
    private RecyclerView rvMembers;
    private MemberAdapter adapter;
    private List<String> tempMembers = new ArrayList<>();

    private String selectedDateIso = ""; // YYYY-MM format for DB

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_setup);

        dbHelper = new DatabaseHelper(this);

        if (dbHelper.isSetupDone()) {
            startActivity(new Intent(this, DashboardActivity.class));
            finish();
            return;
        }

        initViews();
    }

    private void initViews() {
        etName = findViewById(R.id.etAssocName);
        etAmount = findViewById(R.id.etAmount);
        etDate = findViewById(R.id.etStartDate);
        etMemberName = findViewById(R.id.etMemberName);
        btnAddMember = findViewById(R.id.btnAddMember);
        btnSave = findViewById(R.id.btnSave);
        rvMembers = findViewById(R.id.rvSetupMembers);

        // Date Picker Logic
        etDate.setOnClickListener(v -> showDatePicker());

        // Setup RecyclerView
        adapter = new MemberAdapter();
        rvMembers.setLayoutManager(new LinearLayoutManager(this));
        rvMembers.setAdapter(adapter);

        btnAddMember.setOnClickListener(v -> {
            String name = etMemberName.getText().toString().trim();
            if (!name.isEmpty()) {
                tempMembers.add(name);
                adapter.notifyItemInserted(tempMembers.size() - 1);
                etMemberName.setText("");
            }
        });

        btnSave.setOnClickListener(v -> saveAndStart());
    }

    private void showDatePicker() {
        final Calendar c = Calendar.getInstance();
        int year = c.get(Calendar.YEAR);
        int month = c.get(Calendar.MONTH);
        int day = c.get(Calendar.DAY_OF_MONTH);

        DatePickerDialog datePickerDialog = new DatePickerDialog(this,
                (view, year1, monthOfYear, dayOfMonth) -> {
                    // Store as YYYY-MM for logic consistency
                    selectedDateIso = String.format(Locale.US, "%d-%02d", year1, monthOfYear + 1);
                    // Display friendly format
                    etDate.setText(String.format(Locale.US, "%d/%d/%d", dayOfMonth, monthOfYear + 1, year1));
                }, year, month, day);
        datePickerDialog.show();
    }

    private void saveAndStart() {
        String name = etName.getText().toString().trim();
        String amountStr = etAmount.getText().toString().trim();

        if (name.isEmpty() || amountStr.isEmpty() || selectedDateIso.isEmpty() || tempMembers.size() < 2) {
            Toast.makeText(this, "الرجاء إكمال البيانات وإضافة عضوين على الأقل", Toast.LENGTH_LONG).show();
            return;
        }

        dbHelper.saveSetting(DatabaseHelper.KEY_ASSOC_NAME, name);
        dbHelper.saveSetting(DatabaseHelper.KEY_AMOUNT, amountStr);
        dbHelper.saveSetting(DatabaseHelper.KEY_START_DATE, selectedDateIso);
        dbHelper.saveSetting(DatabaseHelper.KEY_CURRENT_MONTH_IDX, "0");

        for (int i = 0; i < tempMembers.size(); i++) {
            dbHelper.addMember(tempMembers.get(i), i);
        }

        startActivity(new Intent(this, DashboardActivity.class));
        finish();
    }

    class MemberAdapter extends RecyclerView.Adapter<MemberAdapter.VH> {
        @NonNull
        @Override
        public VH onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
            View v = LayoutInflater.from(parent.getContext()).inflate(android.R.layout.simple_list_item_1, parent, false);
            return new VH(v);
        }

        @Override
        public void onBindViewHolder(@NonNull VH holder, int position) {
            holder.text.setText((position + 1) + ". " + tempMembers.get(position));
        }

        @Override
        public int getItemCount() { return tempMembers.size(); }

        class VH extends RecyclerView.ViewHolder {
            TextView text;
            public VH(View itemView) {
                super(itemView);
                text = itemView.findViewById(android.R.id.text1);
            }
        }
    }
}

package com.example.jamiya;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;
import java.util.ArrayList;
import java.util.List;

public class DatabaseHelper extends SQLiteOpenHelper {

    private static final String DATABASE_NAME = "Jamiya.db";
    private static final int DATABASE_VERSION = 2;

    // Table: Members
    private static final String TABLE_MEMBERS = "members";
    private static final String COL_ID = "id";
    private static final String COL_NAME = "name";
    private static final String COL_ORDER = "payout_order";

    // Table: Payments
    private static final String TABLE_PAYMENTS = "payments";
    private static final String COL_MEMBER_ID = "member_id";
    private static final String COL_MONTH_INDEX = "month_index";
    private static final String COL_IS_PAID = "is_paid";

    // Table: Settings
    private static final String TABLE_SETTINGS = "settings";
    private static final String COL_KEY = "key";
    private static final String COL_VALUE = "value";

    // Keys
    public static final String KEY_ASSOC_NAME = "assoc_name";
    public static final String KEY_START_DATE = "start_date"; // YYYY-MM
    public static final String KEY_AMOUNT = "amount";
    public static final String KEY_CURRENT_MONTH_IDX = "current_month_idx";

    public DatabaseHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }

    @Override
    public void onCreate(SQLiteDatabase db) {
        String createMembers = "CREATE TABLE " + TABLE_MEMBERS + " (" +
                COL_ID + " INTEGER PRIMARY KEY AUTOINCREMENT, " +
                COL_NAME + " TEXT, " +
                COL_ORDER + " INTEGER)";

        String createPayments = "CREATE TABLE " + TABLE_PAYMENTS + " (" +
                COL_MEMBER_ID + " INTEGER, " +
                COL_MONTH_INDEX + " INTEGER, " +
                COL_IS_PAID + " INTEGER, " +
                "PRIMARY KEY (" + COL_MEMBER_ID + ", " + COL_MONTH_INDEX + "))";

        String createSettings = "CREATE TABLE " + TABLE_SETTINGS + " (" +
                COL_KEY + " TEXT PRIMARY KEY, " +
                COL_VALUE + " TEXT)";

        db.execSQL(createMembers);
        db.execSQL(createPayments);
        db.execSQL(createSettings);
    }

    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_MEMBERS);
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_PAYMENTS);
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_SETTINGS);
        onCreate(db);
    }

    // --- Settings Operations ---

    public void saveSetting(String key, String value) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_KEY, key);
        values.put(COL_VALUE, value);
        db.replace(TABLE_SETTINGS, null, values);
    }

    public String getSetting(String key) {
        SQLiteDatabase db = this.getReadableDatabase();
        Cursor cursor = db.query(TABLE_SETTINGS, new String[]{COL_VALUE}, COL_KEY + "=?", new String[]{key}, null, null, null);
        String val = null;
        if (cursor.moveToFirst()) val = cursor.getString(0);
        cursor.close();
        return val;
    }

    public boolean isSetupDone() {
        return getSetting(KEY_ASSOC_NAME) != null;
    }

    public void resetAllData() {
        SQLiteDatabase db = this.getWritableDatabase();
        db.delete(TABLE_MEMBERS, null, null);
        db.delete(TABLE_PAYMENTS, null, null);
        db.delete(TABLE_SETTINGS, null, null);
    }

    // --- Member Operations ---

    public void addMember(String name, int order) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_NAME, name);
        values.put(COL_ORDER, order);
        db.insert(TABLE_MEMBERS, null, values);
    }

    public void updateMemberName(int id, String newName) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_NAME, newName);
        db.update(TABLE_MEMBERS, values, COL_ID + "=?", new String[]{String.valueOf(id)});
    }

    public void deleteMember(int id) {
        SQLiteDatabase db = this.getWritableDatabase();
        db.delete(TABLE_MEMBERS, COL_ID + "=?", new String[]{String.valueOf(id)});
        db.delete(TABLE_PAYMENTS, COL_MEMBER_ID + "=?", new String[]{String.valueOf(id)});
    }

    public List<Member> getAllMembers() {
        List<Member> members = new ArrayList<>();
        SQLiteDatabase db = this.getReadableDatabase();
        Cursor cursor = db.rawQuery("SELECT * FROM " + TABLE_MEMBERS + " ORDER BY " + COL_ORDER + " ASC", null);

        if (cursor.moveToFirst()) {
            do {
                Member member = new Member();
                member.setId(cursor.getInt(cursor.getColumnIndexOrThrow(COL_ID)));
                member.setName(cursor.getString(cursor.getColumnIndexOrThrow(COL_NAME)));
                member.setOrder(cursor.getInt(cursor.getColumnIndexOrThrow(COL_ORDER)));
                members.add(member);
            } while (cursor.moveToNext());
        }
        cursor.close();
        return members;
    }

    // --- Payment Operations ---

    public boolean isMemberPaid(int memberId, int monthIndex) {
        SQLiteDatabase db = this.getReadableDatabase();
        Cursor cursor = db.rawQuery("SELECT " + COL_IS_PAID + " FROM " + TABLE_PAYMENTS + 
                " WHERE " + COL_MEMBER_ID + "=? AND " + COL_MONTH_INDEX + "=?", 
                new String[]{String.valueOf(memberId), String.valueOf(monthIndex)});

        boolean paid = false;
        if (cursor.moveToFirst()) {
            paid = cursor.getInt(0) == 1;
        }
        cursor.close();
        return paid;
    }

    public void setPaymentStatus(int memberId, int monthIndex, boolean isPaid) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_MEMBER_ID, memberId);
        values.put(COL_MONTH_INDEX, monthIndex);
        values.put(COL_IS_PAID, isPaid ? 1 : 0);
        db.replace(TABLE_PAYMENTS, null, values);
    }

    // --- Logic Helpers ---
    public int getCurrentMonthIndex() {
        String val = getSetting(KEY_CURRENT_MONTH_IDX);
        return val == null ? 0 : Integer.parseInt(val);
    }

    public void incrementCurrentMonth() {
        int current = getCurrentMonthIndex();
        saveSetting(KEY_CURRENT_MONTH_IDX, String.valueOf(current + 1));
    }
}

